namespace sv_59f7773bba73425f9183c3e31ad1416f.Services;

/// <summary>
/// Scoped service that polls for low-stock alerts.
/// Polling is driven by the dashboard page; results are broadcast
/// to every subscribed component via <see cref="OnAlertCountChanged"/>.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int CurrentAlertCount { get; private set; }

    /// <summary>
    /// Fired whenever new alert data arrives. Subscribers must wrap
    /// <c>StateHasChanged</c> in <c>InvokeAsync</c> because this fires
    /// from a background thread.
    /// </summary>
    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
    }

    /// <summary>Simulates a database query — returns a random count 0–15.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Call when a component that needs live data becomes visible.
    /// Starts the 10-second polling loop on the first subscriber.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            _ = PollLoopAsync(_cts.Token);
        }
    }

    /// <summary>
    /// Call when a component that needs live data is disposed.
    /// Stops the polling loop when the last subscriber leaves.
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _cts?.Cancel();
            _timer?.Dispose();
            _timer = null;
        }
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fetch immediately on start, then every tick.
        await FetchAndNotifyAsync();

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer!.WaitForNextTickAsync(ct))
                    break;

                await FetchAndNotifyAsync();
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private async Task FetchAndNotifyAsync()
    {
        CurrentAlertCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnAlertCountChanged?.Invoke();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _timer?.Dispose();
    }
}

