@rendermode InteractiveServer
@inject WarehouseState Warehouse
@implements IDisposable

<select class="form-select form-select-sm" value="@Warehouse.CurrentWarehouseId"
        @onchange="OnWarehouseChanged" style="width:auto;">
    @foreach (var wh in WarehouseState.AvailableWarehouses)
    {
        <option value="@wh.Key">@wh.Value</option>
    }
</select>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            Warehouse.SetWarehouse(id);
        }
    }

    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        Warehouse.OnChange += _handler;
    }

    public void Dispose() => Warehouse.OnChange -= _handler;
}

@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.CurrentAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill">@AlertService.CurrentAlertCount</span>
}
else
{
    <span class="badge bg-success rounded-pill">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _handler;
    }

    public void Dispose() => AlertService.OnAlertCountChanged -= _handler;
}

