@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseState Warehouse
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @Warehouse.CurrentWarehouseName</PageTitle>

<h1>@Warehouse.CurrentWarehouseName — Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 @(AlertService.CurrentAlertCount > 0 ? "text-danger" : "text-success")">
                    @AlertService.CurrentAlertCount
                </p>
                <p class="text-muted">items below minimum level</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Site</h5>
                <p class="display-6">@Warehouse.CurrentWarehouseId</p>
                <p class="text-muted">@Warehouse.CurrentWarehouseName</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="display-6 text-success">● Active</p>
                <p class="text-muted">refreshing every 10 s</p>
            </div>
        </div>
    </div>
</div>

@code {
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        _alertHandler = () => InvokeAsync(StateHasChanged);

        Warehouse.OnChange += _warehouseHandler;
        AlertService.OnAlertCountChanged += _alertHandler;

        AlertService.StartPolling();
    }

    public void Dispose()
    {
        Warehouse.OnChange -= _warehouseHandler;
        AlertService.OnAlertCountChanged -= _alertHandler;

        AlertService.StopPolling();
    }
}

